from sentence_transformers import CrossEncoder

reranker = CrossEncoder(
    "BAAI/bge-reranker-base"
)



def reRank(query, retrievals: list[dict]):
    print('re-ranker started')

    pairs = [
        (query, chunk["text"]) for chunk in retrievals
    ]
    
    scores = reranker.predict(pairs)
    
    for chunk, score in zip(retrievals, scores):
        chunk["rerank_score"] = float(score)
        
        
    retrievals.sort(
        key=lambda x: x["rerank_score"],
        reverse=True
    )
    results = retrievals[:5]
    print('re-ranker ended')
    print(results)
    
    
